func TestTranslateDockerMetrics(t *testing.T) {
	testCases := []struct {
		testName                     string
		originalNames                []string
		translatedNames              []string
		originalResourceAttributes   map[string]string
		translatedResourceAttributes map[string]any
		shouldTranslate              bool
	}{
		{
